cd $WORKSPACE_DIR && python3 -c "
from docx import Document
doc = Document('output/tax-issue-identification-report.docx')
fulltext = '\n'.join(p.text for p in doc.paragraphs)
for t in doc.tables:
    for row in t.rows:
        for cell in row.cells:
            fulltext += '\n' + cell.text
# Find all occurrences of 3.8M, 6.3M, 22.1M and show context
import re
for term in ['3.8M','6.3M','22.1M']:
    for m in re.finditer(term, fulltext):
        s=max(0,m.start()-40); e=min(len(fulltext),m.end()+40)
        print(f'{term} @ {m.start()}: ...{fulltext[s:e]}...')
    print()
" 2>&1
